import "../../Stylesheets/LandingPage/Faixa.css";

export default function Faixa() {
  return (
    <div className="inline-flex items-center justify-evenly bg-branco w-full he">
      <div className="fx-conteudo">
        <h1>
          <span>A Corrida dos DEVs</span>, site que pretende avaliar
          objetivamente estudantes de programação;
        </h1>
        <p>
          também temos como objetivo estimular o desenvolvimento acadêmico para
          construir profissionais de qualidade.
        </p>
      </div>
      <button type="button" className="fx-btn btn">
        Confira o Ranking
      </button>
    </div>
  );
}
